INSERT INTO categories (parent_id, slug, path, name, description, sort_order, is_active, source_type, source_key, import_batch_id, created_at, updated_at)
SELECT (SELECT id FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations' LIMIT 1), 'catholicism', 'society/religion-and-spirituality/christianity/denominations/catholicism', 'Catholicism', 'I believe in one, holy, catholic, apostolic Church.   This category contains links to various web pages concerning the Catholic Church. Using the common terminology, Catholic here refers to all those churches in communion with the Bishop of Rome, Pope Benedict XVI. Roman Catholics and Eastern Catholics (of all rites) are found here.   For pages concerning Catholic churches not in union with Rome (Polish National Catholic Church, etc.), please see the \"Not in Communion with Rome\" subcategory. ', 0, 1, 'dmoz_import', '993380', @import_batch_id, NOW(), NOW()
WHERE NOT EXISTS (SELECT 1 FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/catholicism' LIMIT 1);

INSERT INTO categories (parent_id, slug, path, name, description, sort_order, is_active, source_type, source_key, import_batch_id, created_at, updated_at)
SELECT (SELECT id FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations' LIMIT 1), 'holiness', 'society/religion-and-spirituality/christianity/denominations/holiness', 'Holiness', NULL, 0, 1, 'dmoz_import', NULL, @import_batch_id, NOW(), NOW()
WHERE NOT EXISTS (SELECT 1 FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/holiness' LIMIT 1);

INSERT INTO categories (parent_id, slug, path, name, description, sort_order, is_active, source_type, source_key, import_batch_id, created_at, updated_at)
SELECT (SELECT id FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations' LIMIT 1), 'lutheran', 'society/religion-and-spirituality/christianity/denominations/lutheran', 'Lutheran', 'The Christian Church in western Europe during the early 1500\'s underwent a reformation. The leading exponent of the reformation was <a href=\"/Society/Religion_and_Spirituality/Christianity/Church_History/The_Reformation/Lutheran_Reformation/Luther,_Martin\">Martin Luther</a>. The reformation movement ultimately lead to a complete split between the reformers and the Roman Catholic Church. Those who joined the reformers were later called Protestants as they protested the authority over the Church maintained by the Pope. Those who follow the theology of Martin Luther, the Augsburg Confession and the Book of Concord are called Lutherans. Protestantism as a whole has fractured into many denominations. Those claiming the mantle of Luther have not avoided divisions over doctrinal questions and as a consequence there are a significant number of Lutheran Denominations.  Lutheranism has been the predominant denomination in Northern Germany, and Scandinavia where it is the established (state) church. Lutheran denominations are also prominent in North America.<br> The Lutheran Church began with an emphasis on literacy, scholarship, music, and liturgical worship that continues to this day. ', 0, 1, 'dmoz_import', '990767', @import_batch_id, NOW(), NOW()
WHERE NOT EXISTS (SELECT 1 FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/lutheran' LIMIT 1);

INSERT INTO categories (parent_id, slug, path, name, description, sort_order, is_active, source_type, source_key, import_batch_id, created_at, updated_at)
SELECT (SELECT id FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations' LIMIT 1), 'methodist', 'society/religion-and-spirituality/christianity/denominations/methodist', 'Methodist', 'Methodism has at its roots one person whose vision, determination and faith inspired fellow seekers to re-assess their lives and renew their relationship with God. John Wesley (1703-1791) challenged the religious assumptions of his day, urging those to whom he preached to \'trust in Christ, Christ alone for salvation\' for the assurance that we are all forgiven through Christ.       When John Wesley was at Oxford University, he was part of a small group of students who met regularly and \'methodically\' for prayer, Bible study and Holy Communion. This earned them the nickname \'The Holy Club\' or \'Methodists\'.       Wesley became a priest in the Church of England, but in 1738 had a spiritual experience that he described as God working in his heart through faith in Christ. He launched a hugely influential preaching ministry and had a flair for organising people into small groups. These he named classes, with locally appointed preachers and leaders, which studied the gospels and prayed together. Wesley\'s new movement became a separate Church which grew rapidly throughout the 18th century and afterwards.   One of the most important distinctions from Calvin and the doctrine of predestination was the doctrine of prevenient grace and its basis in the Arminian view of free will. The United Methodist Church in their book of discipline for 2004 said prevenient grace is \"the divine love that surrounds all humanity and precedes any and all of our conscious impulses. This grace prompts our first wish to please God, our first glimmer of understanding concerning God\'s will, and our \'first slight transient conviction\' of having sinned against God. God\'s grace also awakens in us an earnest longing for deliverance from sin and death and moves us toward repentance and faith.\"  Wesley\'s theology often characterised by the four \"alls\" 1. All need to be saved. 2. All can be saved. 3. All can know they are saved. 4. All can be saved to the full, to the uttermost.   ', 0, 1, 'dmoz_import', '992655', @import_batch_id, NOW(), NOW()
WHERE NOT EXISTS (SELECT 1 FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/methodist' LIMIT 1);

INSERT INTO categories (parent_id, slug, path, name, description, sort_order, is_active, source_type, source_key, import_batch_id, created_at, updated_at)
SELECT (SELECT id FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations' LIMIT 1), 'presbyterian', 'society/religion-and-spirituality/christianity/denominations/presbyterian', 'Presbyterian', 'Rooted in the Church of Scotland, \"Presbyterian\" describes Christian churches that conform to a governmental structure involving \"presbyters,\" or elders. These elders are a part of a structure that involves regional gatherings of churches, known as \"presbyteries,\" and often regional gatherings of presbyteries, known as \"synods.\" Each denomination known as \"Presbyterian\" varies somewhat in its particular governmental structure, but \"Presbyterian\" describes this congregational connection to a larger body as the primary feature of church government rather than a particular set of beliefs.    Beliefs vary widely among Presbyterian denominations. See their individual categories for more information on beliefs, specific church structure, and individual congregations. ', 0, 1, 'dmoz_import', '991174', @import_batch_id, NOW(), NOW()
WHERE NOT EXISTS (SELECT 1 FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/presbyterian' LIMIT 1);

