INSERT INTO categories (parent_id, slug, path, name, description, sort_order, is_active, source_type, source_key, import_batch_id, created_at, updated_at)
SELECT (SELECT id FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/methodist' LIMIT 1), 'united-methodist', 'society/religion-and-spirituality/christianity/denominations/methodist/united-methodist', 'United_Methodist', 'The United Methodist Church is the largest of the churches of the Wesleyan tradition.  Originating in the United States under the leadership of John Wesley and Francis Asbury, it is now growing most rapidly in Africa and has a significant presence throughout the world. The UMC is the successor in the United States to the Methodist Church and the Evangelical United Brethren, which merged in the 1960s.   ', 0, 1, 'dmoz_import', '992689', @import_batch_id, NOW(), NOW()
