SELECT (SELECT id FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/presbyterian' LIMIT 1), 'presbyterian-church-usa', 'society/religion-and-spirituality/christianity/denominations/presbyterian/presbyterian-church-usa', 'Presbyterian_Church_USA', 'The <a href=\"http://www.pcusa.org/\">Presbyterian Church (USA)</a> is the largest Presbyterian denomination in the United States with over 2.5 million members across the country.            Formed in 1983 with the merger of the United Presbyterian Church in the United States of America (\"northern church\") and the Presbyterian Church in the United States (\"southern church\"), the PC(USA) maintains its national offices in <a href=\"/Regional/North_America/United_States/Kentucky/Localities/L/Louisville/\">Louisville, Kentucky</a>. ', 0, 1, 'dmoz_import', '991226', @import_batch_id, NOW(), NOW()
WHERE NOT EXISTS (SELECT 1 FROM categories WHERE path = 'society/religion-and-spirituality/christianity/denominations/presbyterian/presbyterian-church-usa' LIMIT 1);

